SELECT v.vehicle_id, v.user_id, v.household_id, v.license_plate, v.car_model, v.car_type, v.status, v.approved_by, v.approved_at, v.created_at, h.dong, h.ho, u.name AS user_name FROM vehicle v LEFT JOIN household h ON v.household_id = h.household_id LEFT JOIN user u ON v.user_id = u.user_id
AND v.deleted_at IS NULL AND v.household_id = #{req.householdId} AND v.status = #{req.status} AND v.car_type = #{req.carType} AND h.dong = #{req.dong}
AND (v.license_plate LIKE CONCAT('%', #{req.search}, '%') OR v.car_model LIKE CONCAT('%', #{req.search}, '%') OR h.dong LIKE CONCAT('%', #{req.search}, '%'))
ORDER BY v.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM vehicle v
LEFT JOIN household h ON v.household_id = h.household_id

    AND v.deleted_at IS NULL
    AND v.household_id = #{householdId}
    AND v.status = #{status}
    AND v.car_type = #{carType}
    AND h.dong = #{dong}

        AND (v.license_plate LIKE CONCAT('%', #{search}, '%')
        OR v.car_model     LIKE CONCAT('%', #{search}, '%')
        OR h.dong          LIKE CONCAT('%', #{search}, '%'))

SELECT COUNT(*) FROM vehicle
WHERE status = #{status}
  AND deleted_at IS NULL

SELECT household_id
FROM user
WHERE user_id = #{userId}
